     1→package api
     2→
     3→import (
     4→	"context"
     5→	"net/http"
     6→	"strconv"
     7→	"time"
     8→)
     9→
    10→// DashboardStats holds aggregate statistics for the dashboard.
    11→type DashboardStats struct {
    12→	TotalReleases    int `json:"total_releases"`
    13→	ActiveSources    int `json:"active_sources"`
    14→	TotalProjects    int `json:"total_projects"`
    15→	PendingAgentRuns int `json:"pending_agent_runs"`
    16→	ReleasesThisWeek int `json:"releases_this_week"`
    17→	AttentionNeeded  int `json:"attention_needed"`
    18→}
    19→
    20→// TrendBucket represents a single time bucket in the release trend.
    21→type TrendBucket struct {
    22→	Period           string `json:"period"`
    23→	Releases         int    `json:"releases"`
    24→	SemanticReleases int    `json:"semantic_releases"`
    25→}
    26→
    27→// TrendResponse is the response payload for the trend endpoint.
    28→type TrendResponse struct {
    29→	Granularity string        `json:"granularity"`
    30→	Buckets     []TrendBucket `json:"buckets"`
    31→}
    32→
    33→// HealthChecker defines operations for health checks and dashboard statistics.
    34→type HealthChecker interface {
    35→	PingDB(ctx context.Context) error
    36→	GetStats(ctx context.Context) (*DashboardStats, error)
    37→	GetTrend(ctx context.Context, granularity string, start, end time.Time) ([]TrendBucket, error)
    38→}
    39→
    40→// HealthHandler implements HTTP handlers for health and stats endpoints.
    41→type HealthHandler struct {
    42→	checker HealthChecker
    43→}
    44→
    45→// NewHealthHandler returns a new HealthHandler.
    46→func NewHealthHandler(checker HealthChecker) *HealthHandler {
    47→	return &HealthHandler{checker: checker}
    48→}
    49→
    50→// Check handles GET /health — pings the database and returns health status.
    51→func (h *HealthHandler) Check(w http.ResponseWriter, r *http.Request) {
    52→	err := h.checker.PingDB(r.Context())
    53→	if err != nil {
    54→		RespondJSON(w, r, http.StatusServiceUnavailable, map[string]any{
    55→			"status": "unhealthy",
    56→			"checks": map[string]string{
    57→				"database": "error",
    58→			},
    59→		})
    60→		return
    61→	}
    62→	RespondJSON(w, r, http.StatusOK, map[string]any{
    63→		"status": "healthy",
    64→		"checks": map[string]string{
    65→			"database": "ok",
    66→		},
    67→	})
    68→}
    69→
    70→// Stats handles GET /stats — returns aggregate dashboard statistics.
    71→func (h *HealthHandler) Stats(w http.ResponseWriter, r *http.Request) {
    72→	stats, err := h.checker.GetStats(r.Context())
    73→	if err != nil {
    74→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to retrieve stats")
    75→		return
    76→	}
    77→	RespondJSON(w, r, http.StatusOK, stats)
    78→}
    79→
    80→// Trend handles GET /api/v1/stats/trend — returns time-bucketed release counts.
    81→// Query params:
    82→//   - granularity: "daily" (default), "weekly", or "monthly"
    83→//   - days: number of days to look back (default 7, max 365)
    84→func (h *HealthHandler) Trend(w http.ResponseWriter, r *http.Request) {
    85→	granularity := r.URL.Query().Get("granularity")
    86→	if granularity == "" {
    87→		granularity = "daily"
    88→	}
    89→
    90→	switch granularity {
    91→	case "daily", "weekly", "monthly":
    92→	default:
    93→		RespondError(w, r, http.StatusBadRequest, "invalid_granularity", "granularity must be daily, weekly, or monthly")
    94→		return
    95→	}
    96→
    97→	days := 7
    98→	if d := r.URL.Query().Get("days"); d != "" {
    99→		parsed, err := strconv.Atoi(d)
   100→		if err != nil || parsed < 1 || parsed > 365 {
   101→			RespondError(w, r, http.StatusBadRequest, "invalid_days", "days must be an integer between 1 and 365")
   102→			return
   103→		}
   104→		days = parsed
   105→	}
   106→
   107→	now := time.Now().UTC()
   108→	start := now.AddDate(0, 0, -days)
   109→
   110→	buckets, err := h.checker.GetTrend(r.Context(), granularity, start, now)
   111→	if err != nil {
   112→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to retrieve trend data")
   113→		return
   114→	}
   115→
   116→	RespondJSON(w, r, http.StatusOK, TrendResponse{
   117→		Granularity: granularity,
   118→		Buckets:     buckets,
   119→	})
   120→}
   121→

