     1→// web/components/dashboard/release-trend-chart.tsx
     2→"use client";
     3→
     4→import { useState } from "react";
     5→import useSWR from "swr";
     6→import { system } from "@/lib/api/client";
     7→import {
     8→  BarChart,
     9→  Bar,
    10→  XAxis,
    11→  YAxis,
    12→  Tooltip,
    13→  ResponsiveContainer,
    14→  CartesianGrid,
    15→} from "recharts";
    16→import type { TrendBucket } from "@/lib/api/types";
    17→
    18→type Granularity = "daily" | "weekly" | "monthly";
    19→
    20→const RANGE_OPTIONS = [
    21→  { label: "7d", days: 7, granularity: "daily" as Granularity },
    22→  { label: "30d", days: 30, granularity: "daily" as Granularity },
    23→  { label: "90d", days: 90, granularity: "weekly" as Granularity },
    24→  { label: "1y", days: 365, granularity: "monthly" as Granularity },
    25→];
    26→
    27→function formatPeriod(period: string, granularity: Granularity): string {
    28→  const d = new Date(period + "T00:00:00");
    29→  switch (granularity) {
    30→    case "daily":
    31→      return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
    32→    case "weekly":
    33→      return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
    34→    case "monthly":
    35→      return d.toLocaleDateString("en-US", { month: "short", year: "2-digit" });
    36→  }
    37→}
    38→
    39→export function ReleaseTrendChart() {
    40→  const [rangeIdx, setRangeIdx] = useState(0);
    41→  const range = RANGE_OPTIONS[rangeIdx];
    42→
    43→  const { data, isLoading } = useSWR(
    44→    `trend-${range.granularity}-${range.days}`,
    45→    () => system.trend(range.granularity, range.days)
    46→  );
    47→
    48→  const buckets: TrendBucket[] = data?.data?.buckets ?? [];
    49→
    50→  const chartData = buckets.map((b) => ({
    51→    ...b,
    52→    label: formatPeriod(b.period, range.granularity),
    53→  }));
    54→
    55→  return (
    56→    <div
    57→      className="flex flex-col rounded-lg bg-white px-5 py-4"
    58→      style={{ border: "1px solid #e8e8e5", height: "336px" }}
    59→    >
    60→      <div className="flex items-center justify-between">
    61→        <p
    62→          className="text-xs uppercase tracking-[0.08em]"
    63→          style={{
    64→            fontFamily: "var(--font-dm-sans)",
    65→            fontSize: "12px",
    66→            color: "#6b7280",
    67→          }}
    68→        >
    69→          Release Trend
    70→        </p>
    71→        <div className="flex gap-1">
    72→          {RANGE_OPTIONS.map((opt, idx) => (
    73→            <button
    74→              key={opt.label}
    75→              onClick={() => setRangeIdx(idx)}
    76→              className="rounded px-2 py-0.5 text-xs font-medium transition-colors"
    77→              style={{
    78→                fontFamily: "var(--font-dm-sans)",
    79→                fontSize: "11px",
    80→                backgroundColor:
    81→                  rangeIdx === idx ? "#111113" : "transparent",
    82→                color: rangeIdx === idx ? "#ffffff" : "#6b7280",
    83→                border:
    84→                  rangeIdx === idx
    85→                    ? "1px solid #111113"
    86→                    : "1px solid #e8e8e5",
    87→              }}
    88→            >
    89→              {opt.label}
    90→            </button>
    91→          ))}
    92→        </div>
    93→      </div>
    94→
    95→      <div className="relative mt-3 flex-1" style={{ minHeight: "100px" }}>
    96→        {isLoading ? (
    97→          <div
    98→            className="flex h-full items-center justify-center"
    99→            style={{
   100→              fontFamily: "var(--font-dm-sans)",
   101→              fontSize: "13px",
   102→              color: "#6b7280",
   103→            }}
   104→          >
   105→            Loading...
   106→          </div>
   107→        ) : chartData.length === 0 ? (
   108→          <div
   109→            className="flex h-full items-center justify-center"
   110→            style={{
   111→              fontFamily: "var(--font-dm-sans)",
   112→              fontSize: "13px",
   113→              color: "#b0b0a8",
   114→            }}
   115→          >
   116→            No data yet
   117→          </div>
   118→        ) : (
   119→          <div className="absolute inset-0">
   120→            <ResponsiveContainer width="100%" height="100%">
   121→              <BarChart
   122→                data={chartData}
   123→                margin={{ top: 4, right: 0, bottom: 0, left: -20 }}
   124→                barGap={1}
   125→                barCategoryGap="20%"
   126→              >
   127→                <CartesianGrid
   128→                  strokeDasharray="3 3"
   129→                  stroke="#f0f0ed"
   130→                  vertical={false}
   131→                />
   132→                <XAxis
   133→                  dataKey="label"
   134→                  tick={{ fontSize: 10, fill: "#b0b0a8" }}
   135→                  tickLine={false}
   136→                  axisLine={{ stroke: "#e8e8e5" }}
   137→                  interval="preserveStartEnd"
   138→                />
   139→                <YAxis
   140→                  tick={{ fontSize: 10, fill: "#b0b0a8" }}
   141→                  tickLine={false}
   142→                  axisLine={false}
   143→                  allowDecimals={false}
   144→                />
   145→                <Tooltip
   146→                  contentStyle={{
   147→                    fontFamily: "var(--font-dm-sans)",
   148→                    fontSize: "12px",
   149→                    borderRadius: "6px",
   150→                    border: "1px solid #e8e8e5",
   151→                    boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
   152→                  }}
   153→                  labelStyle={{ fontWeight: 600, color: "#111113" }}
   154→                  cursor={{ fill: "rgba(0,0,0,0.03)" }}
   155→                />
   156→                <Bar
   157→                  dataKey="releases"
   158→                  name="Releases"
   159→                  fill="#e8601a"
   160→                  radius={[2, 2, 0, 0]}
   161→                  maxBarSize={20}
   162→                />
   163→                <Bar
   164→                  dataKey="semantic_releases"
   165→                  name="Semantic Releases"
   166→                  fill="#f4a261"
   167→                  radius={[2, 2, 0, 0]}
   168→                  maxBarSize={20}
   169→                />
   170→              </BarChart>
   171→            </ResponsiveContainer>
   172→          </div>
   173→        )}
   174→      </div>
   175→    </div>
   176→  );
   177→}
   178→

