    15→
    16→function formatEvent(event: SSEEvent): string {
    17→  switch (event.type) {
    18→    case "release":
    19→      return `New release: ${event.data.version}`;
    20→    case "semantic_release":
    21→      return `Semantic release: ${event.data.version} (${event.data.status})`;
    22→    default:
    23→      return "Unknown event";
    24→  }
    25→}
    26→
    27→export function ActivityFeed() {
    28→  const [events, setEvents] = useState<SSEEvent[]>([]);
    29→  const [connected, setConnected] = useState(false);
    30→  const retryRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    31→
    32→  useEffect(() => {
    33→    let es: EventSource | null = null;
    34→
    35→    function connect() {
    36→      try {
    37→        es = new EventSource(`${BASE}/events`);
    38→
    39→        es.onopen = () => setConnected(true);
    40→
    41→        es.onmessage = (msg) => {
    42→          try {
    43→            const event = JSON.parse(msg.data) as SSEEvent;
