// web/components/dashboard/unified-feed.tsx
"use client";

import useSWR from "swr";
import Link from "next/link";
import {
  projects as projectsApi,
  releases as releasesApi,
  sources as sourcesApi,
  semanticReleases as srApi,
} from "@/lib/api/client";
import { VersionChip } from "@/components/ui/version-chip";
import { getProviderIcon } from "@/components/ui/provider-badge";
import { Sparkles } from "lucide-react";
import type { Release, SemanticRelease, Source } from "@/lib/api/types";
import { timeAgo } from "@/lib/format";

type FeedItemType =
  | { kind: "release"; data: Release; repository?: string; provider?: string; projectName?: string }
  | { kind: "semantic"; data: SemanticRelease; projectName?: string };

function getTimestamp(item: FeedItemType): number {
  if (item.kind === "release") {
    return new Date(item.data.released_at ?? item.data.created_at).getTime();
  }
  return new Date(item.data.created_at).getTime();
}

function getTimeStr(item: FeedItemType): string {
  if (item.kind === "release") {
    return item.data.released_at ?? item.data.created_at;
  }
  return item.data.created_at;
}

function ProviderIcon({ provider }: { provider: string }) {
  const icon = getProviderIcon(provider);
  if (!icon) return <div className="h-3.5 w-3.5 shrink-0" />;
  return icon({ size: 14, className: "shrink-0", style: { color: "#9ca3af" } });
}

export function UnifiedFeed() {
  const { data: projectsData } = useSWR("projects-for-dashboard", () =>
    projectsApi.list()
  );

  const { data: feedItems, isLoading } = useSWR(
    projectsData ? "unified-feed" : null,
    async () => {
      if (!projectsData?.data?.length) return [];

      const projectMap = new Map(
        projectsData.data.map((p) => [p.id, p.name])
      );
      const projectSlice = projectsData.data.slice(0, 10);

      // Fetch releases, sources, and semantic releases in parallel
      const [releaseResults, sourceResults, srResults] = await Promise.all([
        Promise.all(
          projectSlice.map((p) =>
            releasesApi.listByProject(p.id, 1).catch(() => null)
          )
        ),
        Promise.all(
          projectSlice.map((p) =>
            sourcesApi.listByProject(p.id, 1).catch(() => null)
          )
        ),
        Promise.all(
          projectSlice.map((p) =>
            srApi.list(p.id, 1).catch(() => null)
          )
        ),
      ]);

      // Build source lookup maps
      const sourceMap = new Map<string, string>();
      const providerMap = new Map<string, string>();
      const sourceProjectMap = new Map<string, string>();
      sourceResults
        .filter((r): r is NonNullable<typeof r> => r !== null)
        .flatMap((r) => r.data)
        .forEach((s: Source) => {
          sourceMap.set(s.id, s.repository);
          providerMap.set(s.id, s.provider);
          sourceProjectMap.set(s.id, s.project_id);
        });

      // Build feed items
      const items: FeedItemType[] = [];

      releaseResults
        .filter((r): r is NonNullable<typeof r> => r !== null)
        .flatMap((r) => r.data)
        .forEach((rel) => {
          const projectId = sourceProjectMap.get(rel.source_id);
          items.push({
            kind: "release",
            data: rel,
            repository: sourceMap.get(rel.source_id),
            provider: providerMap.get(rel.source_id),
            projectName: projectId ? projectMap.get(projectId) : undefined,
          });
        });

      srResults
        .filter((r): r is NonNullable<typeof r> => r !== null)
        .flatMap((r) => r.data)
        .forEach((sr) => {
          items.push({
            kind: "semantic",
            data: sr,
            projectName: projectMap.get(sr.project_id),
          });
        });

      // Sort by timestamp descending, take first 15
      items.sort((a, b) => getTimestamp(b) - getTimestamp(a));
      return items.slice(0, 15);
    }
  );

  if (isLoading) {
    return (
      <div
        className="rounded-lg bg-white py-16 text-center"
        style={{ border: "1px solid #e8e8e5" }}
      >
        <p
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            color: "#6b7280",
          }}
        >
          Loading activity...
        </p>
      </div>
    );
  }

  if (!feedItems || feedItems.length === 0) {
    return null; // Empty state handled by parent
  }

  return (
    <div
      className="flex flex-col rounded-lg bg-white"
      style={{ border: "1px solid #e8e8e5", height: "336px" }}
    >
      {/* Header */}
      <div
        className="flex items-center justify-between px-5 py-4 shrink-0"
        style={{ borderBottom: "1px solid #e8e8e5" }}
      >
        <p
          className="text-xs uppercase tracking-[0.08em]"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "12px",
            color: "#6b7280",
          }}
        >
          Recent Activity
        </p>
      </div>

      {/* Feed items — scrollable */}
      <div className="flex-1 overflow-y-auto">
        {feedItems.map((item, idx) => (
          <FeedEntry
            key={item.kind === "release" ? `r-${item.data.id}` : `sr-${item.data.id}`}
            item={item}
            isLast={idx === feedItems.length - 1}
          />
        ))}
      </div>
    </div>
  );
}

function FeedEntry({ item, isLast }: { item: FeedItemType; isLast: boolean }) {
  if (item.kind === "semantic") {
    const sr = item.data;
    const urgency = sr.report?.urgency?.toUpperCase();
    const isUrgent = urgency === "CRITICAL" || urgency === "HIGH";

    return (
      <Link
        href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
        className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-[#fafaf9]"
        style={{
          borderBottom: isLast ? undefined : "1px solid #e8e8e5",
        }}
      >
        {/* AI icon */}
        <Sparkles className="h-3.5 w-3.5 shrink-0" style={{ color: "#9ca3af" }} />

        {/* Content */}
        <div className="min-w-0 flex-1 flex items-center gap-2">
          <span
            className="truncate"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#6b7280",
            }}
          >
            {item.projectName ?? "Unknown Project"}
          </span>
          {isUrgent && (
            <span
              className="inline-flex items-center rounded px-1 py-0.5 text-[10px] font-semibold leading-none"
              style={{
                backgroundColor: urgency === "CRITICAL" ? "#fff1f2" : "#fff8f0",
                color: urgency === "CRITICAL" ? "#dc2626" : "#d97706",
              }}
            >
              {urgency}
            </span>
          )}
        </div>

        {/* Version + timestamp */}
        <div className="flex items-center gap-3 shrink-0">
          <VersionChip version={sr.version} />
          <span
            className="whitespace-nowrap"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "12px",
              color: "#9ca3af",
            }}
          >
            {timeAgo(getTimeStr({ kind: "semantic", data: sr }))}
          </span>
        </div>
      </Link>
    );
  }

  // Raw release
  const release = item.data;

  return (
    <Link
      href={`/releases/${release.id}`}
      className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-[#fafaf9]"
      style={{
        borderBottom: isLast ? undefined : "1px solid #e8e8e5",
      }}
    >
      {/* Provider icon */}
      {item.provider ? (
        <ProviderIcon provider={item.provider} />
      ) : (
        <div className="h-3.5 w-3.5 shrink-0" />
      )}

      {/* Content */}
      <div className="min-w-0 flex-1 flex items-center gap-2">
        <span
          className="truncate"
          style={{
            fontFamily: "'JetBrains Mono', monospace",
            fontSize: "13px",
            color: "#6b7280",
          }}
        >
          {item.repository ?? release.source_id.slice(0, 12)}
        </span>
        {item.projectName && (
          <span
            className="truncate"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "12px",
              color: "#9ca3af",
            }}
          >
            · {item.projectName}
          </span>
        )}
      </div>

      {/* Version + timestamp */}
      <div className="flex items-center gap-3 shrink-0">
        <VersionChip version={release.version} />
        <span
          className="whitespace-nowrap"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "12px",
            color: "#9ca3af",
          }}
        >
          {timeAgo(release.released_at ?? release.created_at)}
        </span>
      </div>
    </Link>
  );
}

// web/app/page.tsx
"use client";

import useSWR from "swr";
import { StatsCards } from "@/components/dashboard/stats-cards";
import { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
import { UnifiedFeed } from "@/components/dashboard/unified-feed";
import { DashboardEmptyState } from "@/components/dashboard/empty-state";
import { projects as projectsApi } from "@/lib/api/client";

export default function DashboardPage() {
  const { data: projectsData, isLoading } = useSWR("projects-for-dashboard", () =>
    projectsApi.list()
  );

  const hasProjects = !isLoading && projectsData?.data && projectsData.data.length > 0;

  return (
    <div className="space-y-6">
      <h1
        style={{
          fontFamily: "var(--font-fraunces)",
          fontSize: "24px",
          fontWeight: 700,
          color: "#111113",
        }}
      >
        Dashboard
      </h1>

      {hasProjects ? (
        <>
          <StatsCards />
          <div className="grid gap-4 lg:grid-cols-2">
            <ReleaseTrendChart />
            <UnifiedFeed />
          </div>
        </>
      ) : isLoading ? (
        <div
          className="py-16 text-center"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            color: "#6b7280",
          }}
        >
          Loading...
        </div>
      ) : (
        <DashboardEmptyState />
      )}
    </div>
  );
}

// web/lib/api/client.ts
import type {
  ApiResponse,
  Project,
  ProjectInput,
  Release,
  Source,
  SourceInput,
  Subscription,
  SubscriptionInput,
  BatchSubscriptionInput,
  BatchDeleteSubscriptionInput,
  NotificationChannel,
  ChannelInput,
  ContextSource,
  ContextSourceInput,
  SemanticRelease,
  AgentRun,
  HealthStatus,
  Stats,
  TrendData,
} from "./types";

const BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    headers: { "Content-Type": "application/json", ...init?.headers },
    ...init,
  });
  if (!res.ok) {
    const body = await res.json().catch(() => null);
    throw new Error(body?.error?.message ?? `Request failed: ${res.status}`);
  }
  if (res.status === 204) return null as T;
  return res.json();
}

// --- Projects ---

export const projects = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Project[]>>(`/projects?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<Project>>(`/projects/${id}`),
  create: (input: ProjectInput) =>
    request<ApiResponse<Project>>("/projects", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: ProjectInput) =>
    request<ApiResponse<Project>>(`/projects/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/projects/${id}`, { method: "DELETE" }),
};

// --- Sources (nested under projects) ---

export const sources = {
  listByProject: (projectId: string, page = 1) =>
    request<ApiResponse<Source[]>>(`/projects/${projectId}/sources?page=${page}`),
  create: (projectId: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/projects/${projectId}/sources`, {
      method: "POST",
      body: JSON.stringify(input),
    }),
  get: (id: string) =>
    request<ApiResponse<Source>>(`/sources/${id}`),
  update: (id: string, input: SourceInput) =>
    request<ApiResponse<Source>>(`/sources/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/sources/${id}`, { method: "DELETE" }),
  poll: (id: string) =>
    request<ApiResponse<{ new_releases: number }>>(`/sources/${id}/poll`, {
      method: "POST",
    }),
};

export const releases = {
  list: (page = 1, perPage = 25) =>
    request<ApiResponse<Release[]>>(`/releases?page=${page}&per_page=${perPage}`),
  listBySource: (sourceId: string, page = 1) =>
    request<ApiResponse<Release[]>>(`/sources/${sourceId}/releases?page=${page}`),
  listByProject: (projectId: string, page = 1, perPage = 25) =>
    request<ApiResponse<Release[]>>(`/projects/${projectId}/releases?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<Release>>(`/releases/${id}`),
};

// --- Context Sources ---

export const contextSources = {
  list: (projectId: string, page = 1) =>
    request<ApiResponse<ContextSource[]>>(`/projects/${projectId}/context-sources?page=${page}`),
  create: (projectId: string, input: ContextSourceInput) =>
    request<ApiResponse<ContextSource>>(`/projects/${projectId}/context-sources`, {
      method: "POST",
      body: JSON.stringify(input),
    }),
  get: (id: string) =>
    request<ApiResponse<ContextSource>>(`/context-sources/${id}`),
  update: (id: string, input: ContextSourceInput) =>
    request<ApiResponse<ContextSource>>(`/context-sources/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/context-sources/${id}`, { method: "DELETE" }),
};

// --- Semantic Releases ---

export const semanticReleases = {
  listAll: (page = 1, perPage = 25) =>
    request<ApiResponse<SemanticRelease[]>>(`/semantic-releases?page=${page}&per_page=${perPage}`),
  list: (projectId: string, page = 1, perPage = 25) =>
    request<ApiResponse<SemanticRelease[]>>(`/projects/${projectId}/semantic-releases?page=${page}&per_page=${perPage}`),
  get: (id: string) =>
    request<ApiResponse<SemanticRelease>>(`/semantic-releases/${id}`),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/semantic-releases/${id}`, { method: "DELETE" }),
  getSources: (id: string) =>
    request<ApiResponse<Release[]>>(`/semantic-releases/${id}/sources`),
};

// --- Agent ---

export const agent = {
  triggerRun: (projectId: string, version?: string) =>
    request<ApiResponse<AgentRun>>(`/projects/${projectId}/agent/run`, {
      method: "POST",
      body: JSON.stringify({ trigger: "test", version: version || undefined }),
    }),
  listRuns: (projectId: string, page = 1) =>
    request<ApiResponse<AgentRun[]>>(`/projects/${projectId}/agent/runs?page=${page}`),
  getRun: (id: string) =>
    request<ApiResponse<AgentRun>>(`/agent-runs/${id}`),
};

// --- Subscriptions ---

export const subscriptions = {
  list: (page = 1, perPage = 100) =>
    request<ApiResponse<Subscription[]>>(`/subscriptions?page=${page}&per_page=${perPage}`),
  get: (id: string) => request<ApiResponse<Subscription>>(`/subscriptions/${id}`),
  create: (input: SubscriptionInput) =>
    request<ApiResponse<Subscription>>("/subscriptions", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  batchCreate: (input: BatchSubscriptionInput) =>
    request<ApiResponse<Subscription[]>>("/subscriptions/batch", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: SubscriptionInput) =>
    request<ApiResponse<Subscription>>(`/subscriptions/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/subscriptions/${id}`, { method: "DELETE" }),
  batchDelete: (input: BatchDeleteSubscriptionInput) =>
    request<ApiResponse<null>>("/subscriptions/batch", {
      method: "DELETE",
      body: JSON.stringify(input),
    }),
};

// --- Notification Channels ---

export const channels = {
  list: (page = 1, perPage = 100) =>
    request<ApiResponse<NotificationChannel[]>>(`/channels?page=${page}&per_page=${perPage}`),
  get: (id: string) => request<ApiResponse<NotificationChannel>>(`/channels/${id}`),
  create: (input: ChannelInput) =>
    request<ApiResponse<NotificationChannel>>("/channels", {
      method: "POST",
      body: JSON.stringify(input),
    }),
  update: (id: string, input: ChannelInput) =>
    request<ApiResponse<NotificationChannel>>(`/channels/${id}`, {
      method: "PUT",
      body: JSON.stringify(input),
    }),
  delete: (id: string) =>
    request<ApiResponse<null>>(`/channels/${id}`, { method: "DELETE" }),
  test: (id: string) =>
    request<ApiResponse<{ status: string }>>(`/channels/${id}/test`, {
      method: "POST",
    }),
};

// --- System ---

export const system = {
  health: () => request<HealthStatus>("/health"),
  stats: () => request<ApiResponse<Stats>>("/stats"),
  trend: (granularity: "daily" | "weekly" | "monthly" = "daily", days = 7) =>
    request<ApiResponse<TrendData>>(`/stats/trend?granularity=${granularity}&days=${days}`),
};

